  "moduleMigration.docUri": "https://github.com/vrtmrz/obsidian-livesync/blob/main/README.md#how-to-use",
  "moduleMigration.logBulkSendCorrupted": "\uCCAD\uD06C \uC77C\uAD04 \uC804\uC1A1\uC774 \uD65C\uC131\uD654\uB418\uC5C8\uC9C0\uB9CC, \uC774 \uAE30\uB2A5\uC5D0 \uBB38\uC81C\uAC00 \uC788\uC5C8\uC2B5\uB2C8\uB2E4. \uBD88\uD3B8\uC744 \uB4DC\uB824 \uC8C4\uC1A1\uD569\uB2C8\uB2E4. \uC790\uB3D9\uC73C\uB85C \uBE44\uD65C\uC131\uD654\uB418\uC5C8\uC2B5\uB2C8\uB2E4.",
  "moduleMigration.logFetchRemoteTweakFailed": "\uC6D0\uACA9 \uC870\uC815 \uAC12\uC744 \uAC00\uC838\uC624\uB294\uB370 \uC2E4\uD328\uD588\uC2B5\uB2C8\uB2E4",
  "moduleMigration.logLocalDatabaseNotReady": "\uBB38\uC81C\uAC00 \uBC1C\uC0DD\uD588\uC2B5\uB2C8\uB2E4! \uB85C\uCEEC \uB370\uC774\uD130\uBCA0\uC774\uC2A4\uAC00 \uC900\uBE44\uB418\uC9C0 \uC54A\uC558\uC2B5\uB2C8\uB2E4",
  "moduleMigration.logMigratedSameBehaviour": "\uC774\uC804\uACFC \uAC19\uC740 \uBC29\uC2DD\uC73C\uB85C \uB3D9\uC791\uD558\uB3C4\uB85D db:${current}\uB85C \uB370\uC774\uD130 \uAD6C\uC870 \uC804\uD658\uC774 \uC644\uB8CC\uB418\uC5C8\uC2B5\uB2C8\uB2E4",
  "moduleMigration.logMigrationFailed": "${old}\uC5D0\uC11C ${current}\uB85C\uC758 \uB370\uC774\uD130 \uAD6C\uC870 \uC804\uD658\uC774 \uC2E4\uD328\uD588\uAC70\uB098 \uC911\uB2E8\uB418\uC5C8\uC2B5\uB2C8\uB2E4",
  "moduleMigration.logRedflag2CreationFail": "redflag2 \uC0DD\uC131\uC5D0 \uC2E4\uD328\uD588\uC2B5\uB2C8\uB2E4",
  "moduleMigration.logRemoteTweakUnavailable": "\uC6D0\uACA9 \uC870\uC815 \uAC12\uC744 \uAC00\uC838\uC62C \uC218 \uC5C6\uC2B5\uB2C8\uB2E4",
  "moduleMigration.logSetupCancelled": "\uC124\uC815\uC774 \uCDE8\uC18C\uB418\uC5C8\uC2B5\uB2C8\uB2E4. Self-hosted LiveSync\uAC00 \uC124\uC815\uC744 \uAE30\uB2E4\uB9AC\uACE0 \uC788\uC2B5\uB2C8\uB2E4!",
  "moduleMigration.msgFetchRemoteAgain": "\uC774\uBBF8 \uC54C\uACE0 \uACC4\uC2DC\uACA0\uC9C0\uB9CC, Self-hosted LiveSync\uC758 \uAE30\uBCF8 \uB3D9\uC791 \uBC29\uC2DD\uACFC \uB370\uC774\uD130\uBCA0\uC774\uC2A4 \uAD6C\uC870\uAC00 \uBCC0\uACBD\uB418\uC5C8\uC2B5\uB2C8\uB2E4.\n\n\uB2E4\uD589\uD788\uB3C4 \uC5EC\uB7EC\uBD84\uC758 \uB178\uB825 \uB355\uBD84\uC5D0 \uC6D0\uACA9 \uB370\uC774\uD130\uBCA0\uC774\uC2A4\uB294 \uC774\uBBF8 \uC131\uACF5\uC801\uC73C\uB85C \uB370\uC774\uD130 \uAD6C\uC870 \uC804\uD658\uC774 \uC644\uB8CC\uB41C \uAC83\uC73C\uB85C \uBCF4\uC785\uB2C8\uB2E4. \uCD95\uD558\uB4DC\uB9BD\uB2C8\uB2E4!\n\n\uD558\uC9C0\uB9CC \uC544\uC9C1 \uC77C\uBD80 \uCD94\uAC00 \uC791\uC5C5\uC774 \uD544\uC694\uD569\uB2C8\uB2E4. \uC774 \uAE30\uAE30\uC758 \uC124\uC815\uC774 \uC6D0\uACA9 \uB370\uC774\uD130\uBCA0\uC774\uC2A4\uC640 \uD638\uD658\uB418\uC9C0 \uC54A\uC73C\uBBC0\uB85C, \uC6D0\uACA9 \uB370\uC774\uD130\uB97C \uB2E4\uC2DC \uAC00\uC838\uC640\uC57C \uD569\uB2C8\uB2E4. \uC9C0\uAE08 \uC6D0\uACA9 \uB370\uC774\uD130\uBCA0\uC774\uC2A4\uB97C \uB2E4\uC2DC \uAC00\uC838\uC624\uC2DC\uACA0\uC2B5\uB2C8\uAE4C?\n\n___\uCC38\uACE0: \uC124\uC815\uC774 \uBCC0\uACBD\uB418\uACE0 \uB370\uC774\uD130\uBCA0\uC774\uC2A4\uB97C \uB2E4\uC2DC \uBD88\uB7EC\uC624\uAE30 \uC804\uAE4C\uC9C0\uB294 \uB3D9\uAE30\uD654\uAC00 \uBD88\uAC00\uB2A5\uD569\uB2C8\uB2E4.___\n___\uCC38\uACE02: \uCCAD\uD06C\uB294 \uBCC0\uACBD\uC774 \uBD88\uAC00\uB2A5\uD55C \uAD6C\uC870\uC774\uBBC0\uB85C, \uBA54\uD0C0\uB370\uC774\uD130\uC640 \uCC28\uC774\uC810\uB9CC \uAC00\uC838\uC62C \uC218 \uC788\uC2B5\uB2C8\uB2E4.___",
  "moduleMigration.msgInitialSetup": "\uC774 \uAE30\uAE30\uB294 **\uC544\uC9C1 \uCD08\uAE30 \uC124\uC815\uC774 \uC644\uB8CC\uB418\uC9C0 \uC54A\uC558\uC2B5\uB2C8\uB2E4**. \uC9C0\uAE08\uBD80\uD130 \uC124\uC815 \uACFC\uC815\uC744 \uC548\uB0B4\uD574 \uB4DC\uB9AC\uACA0\uC2B5\uB2C8\uB2E4.\n\n\uBAA8\uB4E0 \uB300\uD654 \uB0B4\uC6A9\uC740 \uD074\uB9BD\uBCF4\uB4DC\uC5D0 \uBCF5\uC0AC\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uB098\uC911\uC5D0 \uCC38\uACE0\uD558\uB824\uBA74 Obsidian \uB178\uD2B8\uC5D0 \uBD99\uC5EC\uB123\uAC70\uB098 \uBC88\uC5ED \uB3C4\uAD6C\uB97C \uD65C\uC6A9\uD574 \uBC88\uC5ED\uD558\uC154\uB3C4 \uB429\uB2C8\uB2E4.\n\n\uBA3C\uC800, **Setup URI**\uB97C \uAC00\uC9C0\uACE0 \uACC4\uC2E0\uAC00\uC694?\n\n\uCC38\uACE0: Setup URI\uAC00 \uBB34\uC5C7\uC778\uC9C0 \uC798 \uBAA8\uB974\uC2DC\uACA0\uB2E4\uBA74 [\uBB38\uC11C](${URI_DOC})\uB97C \uCC38\uACE0\uD574 \uC8FC\uC138\uC694.",
  "moduleMigration.msgRecommendSetupUri": "Setup URI\uB97C \uC0DD\uC131\uD574 \uC0AC\uC6A9\uD558\uB294 \uAC83\uC744 \uAC15\uB825\uD788 \uAD8C\uC7A5\uD569\uB2C8\uB2E4.\nSetup URI\uAC00 \uBB34\uC5C7\uC778\uC9C0 \uC798 \uBAA8\uB974\uC2DC\uACA0\uB2E4\uBA74 [\uBB38\uC11C](${URI_DOC})\uB97C \uCC38\uACE0\uD574 \uC8FC\uC138\uC694. \uC911\uC694\uD55C \uB0B4\uC6A9\uC774\uB2C8 \uAF2D \uD655\uC778\uD558\uC2DC\uAE30 \uBC14\uB78D\uB2C8\uB2E4.\n\n\uC9C1\uC811 \uC218\uB3D9 \uC124\uC815\uC744 \uC9C4\uD589\uD558\uC2DC\uACA0\uC2B5\uB2C8\uAE4C?",
  "moduleMigration.msgSinceV02321": "v0.23.21\uBD80\uD130 Self-hosted LiveSync\uC758 \uAE30\uBCF8 \uB3D9\uC791 \uBC29\uC2DD\uACFC \uB370\uC774\uD130\uBCA0\uC774\uC2A4 \uAD6C\uC870\uAC00 \uBCC0\uACBD\uB418\uC5C8\uC2B5\uB2C8\uB2E4. \uC8FC\uC694 \uBCC0\uACBD\uC0AC\uD56D\uC740 \uB2E4\uC74C\uACFC \uAC19\uC2B5\uB2C8\uB2E4:\n\n1. **\uD30C\uC77C\uBA85 \uB300\uC18C\uBB38\uC790 \uAD6C\uBD84 \uCC98\uB9AC**\n   \uC774\uC81C \uD30C\uC77C\uBA85\uC740 \uB300\uC18C\uBB38\uC790\uB97C \uAD6C\uBD84\uD558\uC9C0 \uC54A\uACE0 \uCC98\uB9AC\uB429\uB2C8\uB2E4. \uC774\uB294 \uD30C\uC77C\uBA85 \uAD6C\uBD84\uC744 \uC81C\uB300\uB85C \uC9C0\uC6D0\uD558\uC9C0 \uC54A\uB294 Linux \uBC0F iOS\uB97C \uC81C\uC678\uD55C \uB300\uBD80\uBD84\uC758 \uD50C\uB7AB\uD3FC\uC5D0\uC11C \uC720\uB9AC\uD55C \uBCC0\uD654\uC785\uB2C8\uB2E4.\n   (Linux\uB098 iOS\uC5D0\uC11C\uB294 \uB300\uC18C\uBB38\uC790\uB9CC \uB2E4\uB978 \uD30C\uC77C\uC774 \uC874\uC7AC\uD560 \uACBD\uC6B0 \uACBD\uACE0\uAC00 \uD45C\uC2DC\uB429\uB2C8\uB2E4)\n\n2. **\uCCAD\uD06C \uB9AC\uBE44\uC804 \uAD00\uB9AC \uBC29\uC2DD \uAC1C\uC120**\n   \uCCAD\uD06C\uB294 \uBCC0\uACBD \uBD88\uAC00\uB2A5\uD55C(immutable) \uAD6C\uC870\uB85C \uACE0\uC815\uB418\uBA70, \uC774\uB97C \uD1B5\uD574 \uB9AC\uBE44\uC804 \uCC98\uB9AC\uAC00 \uC548\uC815\uD654\uB418\uACE0 \uD30C\uC77C \uC800\uC7A5 \uC131\uB2A5\uC774 \uD5A5\uC0C1\uB429\uB2C8\uB2E4.\n\n___\uB2E8, \uC704 \uAE30\uB2A5\uC744 \uD65C\uC131\uD654\uD558\uB824\uBA74 \uC6D0\uACA9 \uBC0F \uB85C\uCEEC \uB370\uC774\uD130\uBCA0\uC774\uC2A4\uB97C \uBAA8\uB450 \uC7AC\uAD6C\uC131\uD574\uC57C \uD569\uB2C8\uB2E4. \uC774 \uACFC\uC815\uC740 \uC218 \uBD84\uC774 \uC18C\uC694\uB418\uBBC0\uB85C \uC5EC\uC720\uAC00 \uC788\uC744 \uB54C \uC2E4\uD589\uD558\uC2DC\uB294 \uAC83\uC744 \uAD8C\uC7A5\uD569\uB2C8\uB2E4.___\n\n- \uAE30\uC874 \uBC29\uC2DD\uB300\uB85C \uC720\uC9C0\uD558\uB824\uBA74 `${KEEP}`\uC744 \uC120\uD0DD\uD574 \uC774 \uACFC\uC815\uC744 \uAC74\uB108\uB6F8 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\n- \uC2DC\uAC04\uC774 \uBD80\uC871\uD558\uB2E4\uBA74 `${DISMISS}`\uB97C \uB20C\uB7EC\uC8FC\uC2DC\uBA74 \uB098\uC911\uC5D0 \uB2E4\uC2DC \uC548\uB0B4\uB4DC\uB9AC\uACA0\uC2B5\uB2C8\uB2E4.\n- \uC774\uBBF8 \uB2E4\uB978 \uAE30\uAE30\uC5D0\uC11C \uB370\uC774\uD130\uBCA0\uC774\uC2A4\uB97C \uC7AC\uAD6C\uC131\uD558\uC168\uB2E4\uBA74 `${DISMISS}`\uB97C \uC120\uD0DD\uD55C \uB4A4 \uB2E4\uC2DC \uB3D9\uAE30\uD654\uD574 \uBCF4\uC138\uC694. \uCC28\uC774\uC810\uC774 \uAC10\uC9C0\uB418\uBA74 \uB2E4\uC2DC \uC548\uB0B4\uB4DC\uB9AC\uACA0\uC2B5\uB2C8\uB2E4.",
