  "obsidianLiveSyncSettingTab.logPassphraseNotCompatible": "\uC624\uB958: \uD328\uC2A4\uD504\uB808\uC774\uC988\uAC00 \uC6D0\uACA9 \uC11C\uBC84\uC640 \uD638\uD658\uB418\uC9C0 \uC54A\uC2B5\uB2C8\uB2E4! \uB2E4\uC2DC \uD655\uC778\uD574 \uC8FC\uC138\uC694!",
  "obsidianLiveSyncSettingTab.logRebuildNote": "\uB3D9\uAE30\uD654\uAC00 \uBE44\uD65C\uC131\uD654\uB418\uC5C8\uC2B5\uB2C8\uB2E4. \uC6D0\uD558\uB294 \uACBD\uC6B0 \uAC00\uC838\uC624\uAE30 \uD6C4 \uB2E4\uC2DC \uD65C\uC131\uD654\uD558\uC138\uC694.",
