  "LiveSync could not handle multiple vaults which have same name without different prefix, This should be automatically configured.": "LiveSync \u65E0\u6CD5\u5904\u7406\u5177\u6709\u76F8\u540C\u540D\u79F0\u4F46\u6CA1\u6709\u4E0D\u540C\u524D\u7F00\u7684\u591A\u4E2A\u5E93\u3002\u8FD9\u5E94\u8BE5\u81EA\u52A8\u914D\u7F6E\u3002",
  "logPane.autoScroll": "\u81EA\u52A8\u6EDA\u52A8",
